private static loadEnvFile(
  envFilePaths: string[],
  parser: Parser,
  options: ConfigModuleOptions,
): Record<string, any> {
  let config: Record<string, any> = {};
  for (const envFilePath of envFilePaths) {
    if (fs.existsSync(envFilePath)) {
      config = Object.assign(parser(fs.readFileSync(envFilePath)), config);
      if (options.expandVariables) {
        const expandOptions: DotenvExpandOptions =
          typeof options.expandVariables === 'object'
            ? options.expandVariables
            : {};
        config =
          expand({ ...expandOptions, parsed: config }).parsed || config;
      }
    }
  }
  return config;
}

get<T = any>(
  propertyPath: KeyOf<K>,
  defaultValueOrOptions?: T | ConfigGetOptions,
  options?: ConfigGetOptions,
): T | undefined {
  const internalValue = this.getFromInternalConfig(propertyPath);
  if (!isUndefined(internalValue)) {
    return internalValue;
  }

  const validatedEnvValue = this.getFromValidatedEnv(propertyPath);
  if (!isUndefined(validatedEnvValue)) {
    return validatedEnvValue;
  }
  const defaultValue =
    this.isGetOptionsObject(defaultValueOrOptions as Record<string, any>) &&
    !options
      ? undefined
      : defaultValueOrOptions;

  if (!this._skipProcessEnv) {
    const processEnvValue = this.getFromProcessEnv(
      propertyPath,
      defaultValue,
    );
    if (!isUndefined(processEnvValue)) {
      return processEnvValue;
    }
  }

  return defaultValue as T;
}

verifyAsync<T extends object = any>(
  token: string,
  options?: JwtVerifyOptions
): Promise<T> {
  const verifyOptions = this.mergeJwtOptions({ ...options }, 'verifyOptions');
  const secret = this.getSecretKey(
    token,
    options,
    'publicKey',
    JwtSecretRequestType.VERIFY
  );

  return new Promise((resolve, reject) =>
    Promise.resolve()
      .then(() => secret)
      .then((scrt: GetSecretKeyResult) => {
        jwt.verify(
          token,
          scrt,
          verifyOptions as jwt.VerifyOptions,
          (err, decoded) => (err ? reject(err) : resolve(decoded as T))
        );
      })
      .catch(reject)
  );
}

static inspect<TClass = any>(
  target: Type<TClass>,
  schema: mongoose.Schema<TClass>,
): void {
  let parent = target;

  while (!isUndefined(parent.prototype)) {
    if (parent === Function.prototype) {
      break;
    }
    const virtuals = TypeMetadataStorage.getVirtualsMetadataByTarget(parent);

    virtuals.forEach(({ options, name, getter, setter }) => {
      const virtual = schema.virtual(name, options);

      if (getter) {
        virtual.get(getter);
      }

      if (setter) {
        virtual.set(setter);
      }
    });

    parent = Object.getPrototypeOf(parent);
  }
}

import * as ts from 'typescript';
import { mergePluginOptions } from './merge-options';
import { isFilenameMatched } from './utils/is-filename-matched.util';
import { ModelClassVisitor } from './visitors/model-class.visitor';

const typeClassVisitor = new ModelClassVisitor();

export const before = (options?: Record<string, any>, program?: ts.Program) => {
  options = mergePluginOptions(options);

  return (ctx: ts.TransformationContext): ts.Transformer<any> => {
    return (sf: ts.SourceFile) => {
      if (isFilenameMatched(options.typeFileNameSuffix, sf.fileName)) {
        return typeClassVisitor.visit(sf, ctx, program, options);
      }
      return sf;
    };
  };
};

verify<T extends object = any>(token: string, options?: JwtVerifyOptions): T {
  const verifyOptions = this.mergeJwtOptions({ ...options }, 'verifyOptions');
  const secret = this.getSecretKey(
    token,
    options,
    'publicKey',
    JwtSecretRequestType.VERIFY
  );

  if (secret instanceof Promise) {
    secret.catch(() => {}); // suppress rejection from async provider
    this.logger.warn(
      'For async version of "secretOrKeyProvider", please use "verifyAsync".'
    );
    throw new WrongSecretProviderError();
  }

  return jwt.verify(token, secret, verifyOptions as jwt.VerifyOptions) as T;
}

private static async createMongooseConnection(
  uri: string,
  mongooseOptions: ConnectOptions,
  factoryOptions: {
    lazyConnection?: boolean;
    onConnectionCreate?: MongooseModuleOptions['onConnectionCreate'];
  },
): Promise<Connection> {
  const connection = mongoose.createConnection(uri, mongooseOptions);

  if (factoryOptions?.lazyConnection) {
    return connection;
  }

  factoryOptions?.onConnectionCreate?.(connection);

  return connection.asPromise();
}

async onApplicationShutdown() {
  const connection = this.moduleRef.get<any>(this.connectionName);
  if (connection) {
    await connection.close();
  }
}

export class ModuleFinder {
  constructor(private tree: Tree) {}

  public find(options: FindOptions): Path | null {
    const generatedDirectoryPath: Path = options.path;
    const generatedDirectory: DirEntry = this.tree.getDir(
      generatedDirectoryPath,
    );
    return this.findIn(generatedDirectory);
  }

  private findIn(directory: DirEntry): Path | null {
    if (!directory) {
      return null;
    }
    const moduleFilename: PathFragment = directory.subfiles.find((filename) =>
      /\.module\.(t|j)s$/.test(filename),
    );
    return moduleFilename !== undefined
      ? join(directory.path, moduleFilename.valueOf())
      : this.findIn(directory.parent);
  }
}

constructor(
  @Optional()
  contextOrOptions?: string | ConsoleLoggerOptions,
  @Optional()
  options?: ConsoleLoggerOptions,
) {
  // eslint-disable-next-line prefer-const
  let [context, opts] = isString(contextOrOptions)
    ? [contextOrOptions, options]
    : options
      ? [undefined, options]
      : [contextOrOptions?.context, contextOrOptions];

  opts = opts ?? {};
  opts.logLevels ??= DEFAULT_LOG_LEVELS;
  opts.colors ??= opts.colors ?? (opts.json ? false : isColorAllowed());
  opts.prefix ??= 'Nest';

  this.options = opts;
  this.inspectOptions = this.getInspectOptions();

  if (context) {
    this.context = context;
    this.originalContext = context;
  }
}

protected printAsJson(
  message: unknown,
  options: {
    context: string;
    logLevel: LogLevel;
    writeStreamType?: 'stdout' | 'stderr';
    errorStack?: unknown;
  },
) {
  const logObject = this.getJsonLogObject(message, options);
  const formattedMessage =
    !this.options.colors && this.inspectOptions.compact === true
      ? JSON.stringify(logObject, this.stringifyReplacer)
      : inspect(logObject, this.inspectOptions);
  if (this.options.forceConsole) {
    if (options.writeStreamType === 'stderr') {
      console.error(formattedMessage);
    } else {
      console.log(formattedMessage);
    }
  } else {
    process[options.writeStreamType ?? 'stdout'].write(
      `${formattedMessage}\n`,
    );
  }
}
